var e=[{id:`L3_1`,type:`dialog`,speaker:`GLITCH_SCAVENGER_NULL_B`,text:{KOREA:`올레! 용병 형씨 장비가 아주 휘황찬란한데!`,JPN:`オーレ！　傭兵さん、その装備すげえ豪華だな！`,ENG:`Olleh! Your gear looks great, mercenary!`,TWN:`Ole！傭兵大哥的裝備好像很厲害喔！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:{char_id:`GLITCH_SCAVENGER_NULL_A`,face:`UNIT_IDLE`},C:null,R:{char_id:`GLITCH_SCAVENGER_NULL_B`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_AVOID`,text:{KOREA:`으허억!`,JPN:`うわっ！？`,ENG:`Eeek!`,TWN:`唔唔！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_AVOID`,face:`UNIT_SURPRISE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`GLITCH_SCAVENGER_NULL_A`,text:{KOREA:`저것 좀 봐. 머리에도 팔에도 재밌는 걸 주렁주렁 달고 있어.`,JPN:`見ろよあれ。頭にも腕にも面白いのをぶら下げてるぜ。`,ENG:`Look, he has a lot of interesting stuff on his head and arms.`,TWN:`你看，不只是頭，手臂上也有掛那些有趣的東西。`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:{char_id:`GLITCH_SCAVENGER_NULL_A`,face:`UNIT_IDLE`},C:null,R:{char_id:`GLITCH_SCAVENGER_NULL_B`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`GLITCH_SCAVENGER_NULL_B`,text:{KOREA:`몇 등분으로 나누지? 6등분? 딱 6등분만 하면 되나?`,JPN:`何等分にする？　6等分？　ちょうど6等分にすればいいかな？`,ENG:`How shall we carve him up? Into six pieces? Would six be okay?`,TWN:`要把他分成幾等分？6等分？6等分應該差不多吧？`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:{char_id:`GLITCH_SCAVENGER_NULL_A`,face:`UNIT_IDLE`},C:null,R:{char_id:`GLITCH_SCAVENGER_NULL_B`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`GLITCH_SCAVENGER_NULL_A`,text:{KOREA:`그러면 여섯 명밖에 못 나눠 가지잖아. 순서 정해서 원하는 만큼 썰자.`,JPN:`それじゃ6人分にしかならないだろ？　順番決めて、好きなだけ切ろうぜ。`,ENG:`No, then only six people will have him. Let’s just take turns and take as much as each person wants.`,TWN:`那不就只有六個人可以分到？還是決定好順序，各自砍下想要的部位吧！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:{char_id:`GLITCH_SCAVENGER_NULL_A`,face:`UNIT_IDLE`},C:null,R:{char_id:`GLITCH_SCAVENGER_NULL_B`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`GLITCH_SCAVENGER_NULL_B`,text:{KOREA:`우오오! 너 천재냐?!`,JPN:`うおお！　お前、天才か！？`,ENG:`Wow, you’re a genius!`,TWN:`哇賽！你是天才嗎？！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:{char_id:`GLITCH_SCAVENGER_NULL_A`,face:`UNIT_IDLE`},C:null,R:{char_id:`GLITCH_SCAVENGER_NULL_B`,face:`UNIT_IDLE`}}}},{id:`L15_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_AVOID`,text:{KOREA:`해적 주제에 솔로몬 왕 같은 소릴 하는군! 이거나 가져가시지!`,JPN:`海賊のくせにソロモン王のようなことを言いやがる！　これでも食らっとけ！`,ENG:`A pirate that talks like Solomon? Take this!`,TWN:`現在是在演所羅門王的寶藏嗎？這給你們啦！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_AVOID`,face:`UNIT_SURPRISE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`GLITCH_SCAVENGER_NULL_A`,text:{KOREA:`으음? 뭐야? 다리가 갑자기 뻣뻣해졌는데?`,JPN:`うん？　なんだ？　いきなり足が固まったぞ？`,ENG:`Huh? What’s going on? My legs are stiff.`,TWN:`嗯？怎麼會這樣？我的腳突然動不了？`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:{char_id:`GLITCH_SCAVENGER_NULL_A`,face:`UNIT_IDLE`},C:null,R:{char_id:`GLITCH_SCAVENGER_NULL_B`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`GLITCH_SCAVENGER_NULL_B`,text:{KOREA:`내 팔도 그래!`,JPN:`俺の腕もだ！`,ENG:`So are my arms!`,TWN:`我的手臂也是！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:{char_id:`GLITCH_SCAVENGER_NULL_A`,face:`UNIT_IDLE`},C:null,R:{char_id:`GLITCH_SCAVENGER_NULL_B`,face:`UNIT_IDLE`}}}},{id:`L22_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_AVOID`,text:{KOREA:`남자의 친구, EMP 수류탄이다. 내 비장의 무기지.`,JPN:`紳士のお友達。EMP手榴弾さ。俺の切り札だ。`,ENG:`That was the gentleman's friend; the EMP grenade. My ace in the hole.`,TWN:`這是男人的好朋友 EMP手榴彈，是我的秘密武器！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_AVOID`,face:`UNIT_LAUGH`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_AVOID`,text:{KOREA:`한동안은 꼼짝 못할 테니까 거기서 얌전히 쉬고 있으라고.`,JPN:`しばらく身動きは取れないだろうから、そこで大人しく休んでろ。`,ENG:`You won’t be moving for a while. So relax.`,TWN:`你們會無法動彈一段時間，就乖乖在這裡休息一下吧！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_AVOID`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`GLITCH_SCAVENGER_NULL_C`,text:{KOREA:`어허. 갈 때 가더라도 줄 건 줘야지.`,JPN:`おっと、行く前に渡すもんがあるだろ？`,ENG:`Hey, you still have something we want.`,TWN:`等等，要走可以，但東西還是要留下來！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:{char_id:`GLITCH_SCAVENGER_NULL_D`,face:`UNIT_IDLE`},C:{char_id:`GLITCH_SCAVENGER_NULL_C`,face:`UNIT_IDLE`},R:{char_id:`GLITCH_SCAVENGER_NULL_E`,face:`UNIT_IDLE`}}}},{id:`L32_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_AVOID`,text:{KOREA:`젠장, 어디서 이렇게 끝도 없이 기어 나오는 거야!?`,JPN:`くそっ、どこからこんなに湧いてくるんだ！？`,ENG:`Darn it, is there no end to this?`,TWN:`該死！你又是從哪冒出來的？有完沒完啊？！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`JOHN_MASON_NULL_AVOID`,face:`UNIT_SERIOUS`},R:null}}},{id:`L35_1`,type:`dialog`,speaker:`ROJO_SCAVENGER_NULL_NULL`,text:{KOREA:`으음……!`,JPN:`うむ……！`,ENG:`Ngh!`,TWN:`唔……！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:{char_id:`ROJO_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};